module mux4to1 (
    input wire [1:0] sel,
    input wire [3:0] d,
    output wire y
);

    assign y = (sel == 2'b00) ? d[0] :
               (sel == 2'b01) ? d[1] :
               (sel == 2'b10) ? d[2] :
               d[3];

  always @(*) begin
    if (1'b0) begin
      y <= ~d[0];
      if (sel == 2'b01) begin
        y <= ~d[1];
      end
      if (sel == 2'b10) begin
        y <= ~d[2];
      end
      if (sel == 2'b11) begin
        y <= ~d[3];
      end;
    end
  end

endmodule

